// modules/task/routes/audit-log.ts
import { defineRoute } from 'aether';
import { Task, AuditLogEntry } from '../module.contract';
import { requireUser } from '/lib/auth';
import { query } from '/lib/db';

export default defineRoute({
  method: 'GET',
  path: '/tasks/:taskId/audit-log',
  auth: true,
  async handler(req) {
    const user = await requireUser(req);
    const taskId = req.params.taskId;

    // Validate task ID
    if (!taskId || typeof taskId !== 'string') {
      return err({ code: 'invalid_task_id', message: 'Invalid task ID' });
    }

    // Fetch audit log entries for the task
    try {
      const result = await query<AuditLogEntry[]>(
        `
          SELECT * FROM audit_log WHERE task_id = $1 AND user_id = $2
        `,
        [taskId, user.id]
      );

      if (result.rows.length === 0) {
        return err({ code: 'audit_log_not_found', message: 'No audit log entries found for this task' });
      }

      return ok(result.rows);
    } catch (error) {
      return err({ code: 'database_error', message: 'Failed to fetch audit log entries' });
    }
  },
});

